let input = $input.first().json;
if (input.input && typeof input.input === 'string') { try { input = JSON.parse(input.input); } catch(e) {} }
const errors = [];
if (!input.session_key) errors.push('session_key required');
if (!input.zip || !/^\d{5}$/.test(input.zip)) errors.push('A valid 5-digit ZIP code is required.');
if (!input.issue_type) errors.push('issue_type required');
return { json: { ...input, niche: 'roofing', valid: errors.length === 0, errors } };

const err = $input.first().json;
return { 
  json: {
    success: false,
    error: 'Validation failed',
    details: err.errors.join(', ')
  }
};

const input = $input.first().json;
const zip = input.zip || '';

// Add your serviceable ZIP codes here if you want to restrict service
const allowedZips = []; // Empty array means all ZIPs allowed for now

let serviceable = true;
if (allowedZips.length > 0 && !allowedZips.includes(zip)) {
  serviceable = false;
}

return {
  json: {
    ...input,
    serviceable: serviceable,
    service_message: serviceable ? 'In service area' : 'Out of service area'
  }
};

const input = $input.first().json;
const issue = (input.issue_type || '').toLowerCase();
const urgency = (input.urgency || '').toLowerCase();
let low=150, high=600, action='schedule_diagnostic', cta='A technician needs to assess this on-site.';
let disclaimer = "Preliminary estimate. Actual costs depend on physical inspection.";

if (issue.includes('replace') || issue.includes('new roof') || issue.includes('install')) {
    low = 8500; high = 25000; action = 'schedule_consultation';
    cta = 'I highly recommend a free, no-obligation roof replacement consultation.';
} else if (issue.includes('repair') || issue.includes('leak')) {
    low = 350; high = 1200; action = 'schedule_diagnostic';
    cta = 'We can easily schedule a technician to inspect and patch the leak.';
}

if (urgency.includes('emergency') || urgency.includes('storm')) {
    action = 'dispatch_emergency';
    cta = 'Since this is an emergency, our storm response team will be dispatched ASAP.';
    low = 500; high = 1500; disclaimer = "Emergency tarping/mitigation rates apply.";
}
return { json: { ...input, estimate_low: low, estimate_high: high, estimate_range: "$" + low + " - $" + high, action, disclaimer, next_message: cta } };

const result = $input.first().json;

return {
  json: {
    success: true,
    estimate_data: {
        low: result.estimate_low,
        high: result.estimate_high,
        range: result.estimate_range,
        action: result.action
    },
    disclaimer: result.disclaimer,
    summary: `Based on what you've told me, you can expect costs around ${result.estimate_range}. ${result.next_message}`
  }
};
